const body = $input.item.json.body || $input.item.json;
const action = (body.action || 'add').toLowerCase();
const clean = s => (s || '').toString().replace(/<[^>]*>/g, '').trim().substring(0, 100);
if (action === 'add') {
  const articles = Array.isArray(body.articles) ? body.articles : [body.article].filter(Boolean);
  if (!articles.length) throw new Error('Aucun article fourni');
  const semaine = new Date().toISOString().substring(0, 10);
  return articles.slice(0, 50).map(a => ({
    article: clean(typeof a === 'string' ? a : a.nom || a.article),
    quantite: clean(typeof a === 'object' ? a.quantite : ''),
    semaine,
    action: 'add'
  }));
}
return [{ action: 'generate_plan', semaine: new Date().toISOString().substring(0, 10) }];

const content = $input.item.json.message.content;
let plan;
try {
  const match = content.match(/\{[\s\S]*\}/);
  plan = JSON.parse(match[0]);
} catch(e) {
  plan = { plan_repas: {}, liste_organisee: { Autre: [] } };
}
const jours = ['lundi','mardi','mercredi','jeudi','vendredi'];
const planHtml = jours.map(j => {
  const r = plan.plan_repas[j] || {};
  return `<tr><td><strong>${j.charAt(0).toUpperCase()+j.slice(1)}</strong></td><td>${r.dejeuner || '–'}</td><td>${r.diner || '–'}</td></tr>`;
}).join('');
const listeHtml = Object.entries(plan.liste_organisee || {}).map(([rayon, items]) =>
  `<h3>${rayon}</h3><ul>${(items||[]).map(i => `<li>${i}</li>`).join('')}</ul>`
).join('');
return [{
  json: {
    plan_html: planHtml,
    liste_html: listeHtml
  }
}];
